import{_ as t,o as i,c as a,a1 as o}from"./chunks/framework.BX4nIuL2.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"courses/fab-course/doc/1projectmanage/wix.md","filePath":"courses/fab-course/doc/1projectmanage/wix.md"}'),r={name:"courses/fab-course/doc/1projectmanage/wix.md"};function s(n,e,l,d,c,u){return i(),a("div",null,[...e[0]||(e[0]=[o('<h2 id="_1-description" tabindex="-1">1.DESCRIPTION <a class="header-anchor" href="#_1-description" aria-label="Permalink to &quot;1.DESCRIPTION&quot;">​</a></h2><div align="center">![](https://gitlab.com/picbed/bed/uploads/8877b2dc19a1b09395c2f0f49c93d779/wixlogo.png)</div><p><a href="https://www.wix.com/" target="_blank" rel="noreferrer">Wix.com Ltd.</a> is an Israeli software company, providing cloud-based web development services. It allows users to create HTML5 websites and mobile sites through the use of online drag and drop tools. Along with its headquarters and other offices in Israel, Wix also has offices in Brazil, Canada, Germany, India, Ireland, Lithuania, the United States, and Ukraine.Users can add social plug-ins, e-commerce, online marketing, contact forms, e-mail marketing, and community forums to their web sites using a variety of Wix-developed and third-party applications. The Wix website builder is built on a freemium business model, earning its revenues through premium upgrades.</p><p>Users must purchase premium packages to connect their sites to their own domains, remove Wix ads, access the form builder, add e-commerce capabilities, or buy extra data storage and bandwidth.Wix provides customizable website templates and a drag-and-drop HTML5 web site builder that includes apps, graphics, image galleries, fonts, vectors, animations and other options. Users also may opt to create their web sites from scratch. In October 2013, Wix introduced a mobile editor to allow users to adjust their sites for mobile viewing.</p><h2 id="_2-method" tabindex="-1">2.Method <a class="header-anchor" href="#_2-method" aria-label="Permalink to &quot;2.Method&quot;">​</a></h2><p>1.Sign up for a free wix account</p><ul><li>go to the Wix.com sign up page.</li><li>Register with your email address,Facebook account or Google credentials.</li><li>Click Sign Up and you&#39;re all set. <img src="https://gitlab.com/picbed/bed/uploads/b783f7c8569b9c56376a375f4f8faa08/wix01.png" alt=""></li></ul><p>2.Choose a tool to creat your website.Wix ADI is easier to operate than wix editor,but has less free editing and cannot create a richer web interface. <img src="https://gitlab.com/picbed/bed/uploads/6878484cb6e7606b78669178ccd8a541/wix02.png" alt=""></p><p>3.Choosing the Best Template for Your Site.All the templates are organized into categories for easy browsing. You’ll see: Business and Services, Store, Creative, Community and Blog. Hover over each one to discover subcategories</p><ul><li>Go to the Templates Page.</li><li>Find the category that best fits your business or website idea.</li><li>Select a subcategory if relevant.</li><li>Click View to preview a template or click Edit to start editing <img src="https://gitlab.com/picbed/bed/uploads/8ee714882d77f521d492e014170b8582/wix03.gif" alt=""></li></ul><p>4.Edit website</p><ul><li>Go to your site&#39;s dashboard.</li><li>Click Edit Site next to your site&#39;s name. <img src="https://gitlab.com/picbed/bed/uploads/ae6f246b32fbc15898d0569eb579f160/wix04.webp" alt=""></li></ul><p>5.Start Adding Elements The Wix Editor contains hundreds of stunning, customizable elements that you can use to create your site. Choose from images, text, shapes, strips and more to make your site interesting and beautiful! Click <b>Add</b> on the left side of the Editor to start adding elements <img src="https://gitlab.com/picbed/bed/uploads/9a66c2f03769dcb8cf55e911c06bf69f/wix05.gif" alt=""></p><p>6.Customize Your Elements You can customize all of the elements on your site.Select an element and click the Settings , Design , Layout or Animate icons to customize it. Depending on the element selected, you will see different customization options. Play around with the different settings and options to personalize your elements. <img src="https://gitlab.com/picbed/bed/uploads/6e6ea92aae718d11923a3e9ff91abc86/wix06.png" alt=""></p><p>7.Save, Preview and Publish.You can find the Save, Preview and Publish buttons at the top right of the Editor.</p><ul><li>Save: Click Save regularly so you don&#39;t lose any of your work. Keep in mind, saved changes won’t appear on your site until you click Publish.</li><li>Preview: Click Preview to view how your site looks live.</li><li>Publish: Click Publish in the top right corner when you&#39;re ready for your site to go live. <img src="https://gitlab.com/picbed/bed/uploads/924d5ed2e1820d6b570084d49157ef7e/wix07.png" alt=""></li></ul><p>The above method from <a href="https://374737390.wixsite.com/my-site/%E5%89%AF%E6%9C%AC-arduino" target="_blank" rel="noreferrer">CNFD- team</a></p><h3 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Reference&quot;">​</a></h3><ul><li><a href="https://374737390.wixsite.com/my-site/%E5%89%AF%E6%9C%AC-arduino" target="_blank" rel="noreferrer">CNFD- project</a></li><li><a href="https://support.wix.com/en/?referral=HelpWidgetDashboard" target="_blank" rel="noreferrer">wix support</a></li></ul>',19)])])}const m=t(r,[["render",s]]);export{h as __pageData,m as default};
